  ('pukao-0a2fc18c-moex-00025', 'pukao-0a2fc18c', 'pukao-0a2fc18c-moex-114-6948958a', 'sub-pukao-0a2fc18c-02', NULL, 'single_choice', '社會對公共財的需求線，可以下列何種方式獲得？', '["對公共財個別需求線進行水平加總", "對公共財個別需求線進行垂直加總", "以公共財個別需求中最具需求者為代表", "以公共財個別需求中最有效率者為代表"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:09+00:00", "source_pdf_sha1": "7f60f8d3aafd", "answer_pdf_sha1": "79d6a424ea53", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "419", "s": "0709", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "經建行政"}'::jsonb, NULL),
